SourceCode.Declaration:
/// <summary>
/// Product size import
/// </summary>
public class ETG_Acu_EcoResProdMasterSizeImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_EcoResProdMasterSizeImport  prodSizeImport;

    prodSizeImport = ETG_Acu_EcoResProdMasterSizeImport::construct();

    if (prodSizeImport.prompt())
    {
        prodSizeImport.runOperation();
    }
}

public static ETG_Acu_EcoResProdMasterSizeImport construct()
{
    return new ETG_Acu_EcoResProdMasterSizeImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    EcoResProductMasterSizeEntity       prodSize;
    EcoResProductDisplayProductNumber   prodNum;
    EcoResSizeName                      sizeName;

    prodNum     = conpeek(_con, 1);
    sizeName    = conpeek(_con, 2);

    select firstonly prodSize
        where prodSize.ProductMasterNumber  == prodNum
            && prodSize.ProductSizeId       == sizeName;

    if (!prodSize)
    {
        prodSize.initValue();
        prodSize.ProductMasterNumber   = prodNum;
        prodSize.ProductSizeId          = sizeName;
        prodSize.insert();
    }
}

/// <summary>
/// Import colors
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpProdSize";

    return ret;
}
